+import { resolve } from "@std/path";
+import { ConfigParseError } from "./errors.ts";
+import type { ConfigOptions } from "./types.ts";
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const paths = options.searchPaths ?? [Deno.cwd()];
+  const formats = options.formats ?? [".json", ".rc"];
+  const matches: Array<{ path: string; format: string }> = [];
+
+  for (const searchPath of paths) {
+    for (const format of formats) {
+      const filename = format === ".rc" ? `.${options.name}rc` : `${options.name}${format}`;
+      const path = resolve(searchPath, filename);
+      try {
+        const stat = await Deno.stat(path);
+        if (stat.isFile) matches.push({ path, format });
+      } catch (error) {
+        if (!(error instanceof Deno.errors.NotFound)) throw error;
+      }
+    }
+  }
+
+  if (!matches.length) return { values: {} };
+  const selected = options.mergeConfigs ? matches : [matches[0]];
+  const values: Record<string, unknown> = {};
+  // Later assignments must not replace a value supplied by an earlier path.
+  for (const match of selected) {
+    const content = await Deno.readTextFile(match.path);
+    const parsed = parseConfig(content, match.path, match.format, options.parser);
+    for (const [key, value] of Object.entries(flatten(parsed))) {
+      if (!(key in values)) values[key] = value;
+    }
+  }
+  return { path: selected[0].path, values };
+}
+
+function parseConfig(content: string, path: string, format: string, parser?: ConfigOptions["parser"]): Record<string, unknown> {
+  try {
+    const result = parser ? parser(content) : format === ".json" ? JSON.parse(content) : parseRc(content);
+    if (!isPlainObject(result)) throw new TypeError("Configuration must be a plain object.");
+    return result;
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const rawLine of content.split(/\\r?\
/)) {
+    const line = rawLine.trim();
+    if (!line || line.startsWith("#")) continue;
+    const index = line.indexOf("=");
+    if (index < 0) throw new SyntaxError("Expected key=value.");
+    const key = line.slice(0, index).trim();
+    let value = line.slice(index + 1).trim();
+    if (!key) throw new SyntaxError("Missing key.");
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length === 1) throw new SyntaxError("Unterminated quoted value.");
+      value = value.slice(1, -1);
+    }
+    result[key] = value === "true" ? true : value === "false" ? false :
+      value !== "" && /^[-+]?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value) ? Number(value) : value;
+  }
+  return result;
+}
+
+export function flatten(value: Record<string, unknown>, prefix = ""): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [rawKey, item] of Object.entries(value)) {
+    const key = `${prefix}${camelCase(rawKey)}`;
+    if (isPlainObject(item)) Object.assign(result, flatten(item, `${key}.`));
+    else result[key] = item;
+  }
+  return result;
+}
+
+function camelCase(key: string): string {
+  return key.replace(/-([a-zA-Z0-9])/g, (_, char) => char.toUpperCase());
+}
+
+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  return typeof value === "object" && value !== null && (Object.getPrototypeOf(value) === Object.prototype || Object.getPrototypeOf(value) === null);
+}
